        v.Idx := 0;
      else
        v.Idx := r.Idx + 1;
      end if;
    end if;

    -- *** Latch ***
    if ((r.VldReg(r.VldReg'high) = '1') or (r.LastReg = '1')) and not Blocked_v then
      v.Ovld      := '1';
      v.Odata     := r.DataReg;
      v.Olast     := r.LastReg;
      v.Okeep     := r.VldReg;
      v.VldReg    := (others => '0');
      v.VldReg(0) := vld_i;
      v.LastReg   := vld_i and tdm_last_i;
